parameters.jsCode:
const emails = $input.first().json.Attendees_Gmails
  .split(',')
  .map(e => e.trim())
  .filter(e => e.length > 0);

const totalEmailsCount = emails.length;

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const invalidEmails = emails.filter(email => !emailRegex.test(email));


return [
  {
    totalEmailsCount,
    validEmailsCount: emails.length - invalidEmails.length,
    emails,
    invalidEmails
  }
];

const duration = $('Form to add Meeting Data').first().json.Duration.toLowerCase().trim();

let minutes = 0;

// extract number part
const number = parseFloat(duration);

if (duration.includes('minute')) {
  minutes = number;
} 
else if (duration.includes('hour')) {
  minutes = number * 60;
} 
else {
  throw new Error('Invalid duration format. Use minutes or hours.');
}

return [
  {
    originalDuration: duration,
    durationInMinutes: minutes
  }
];

const existing = $input.all();

const newStart = DateTime.fromISO($('If').first().json['Date/Time']);
const duration = Number($('If').first().json.durationInMinutes);
const newEnd = newStart.plus({ minutes: duration });

const buffer = 60;

let conflict = null;

existing.forEach(r => {
  if (r.json.Status === 'Cancelled') return;

  const exStart = DateTime.fromISO(r.json['Date/Time']);
  const exDuration = Number(r.json['Duration(mins)'] || 60);
  const exEnd = exStart.plus({ minutes: exDuration });

  const gapBefore = newStart.diff(exEnd, 'minutes').minutes;
  const gapAfter = exStart.diff(newEnd, 'minutes').minutes;

  if (gapBefore < buffer && gapAfter < buffer) {
    conflict = {
      title: r.json.Title,   
      startTime: exStart.toISO(),
      duration: exDuration
    };
  }
});

return [
  {
    json: {
      ...$('If').first().json,
      conflict: conflict ? true : false,
      conflictTitle: conflict?.title || '',
      conflictStartTime: conflict?.startTime || null,
      conflictDuration: conflict?.duration || null
    }
  }
];

