parameters.jsCode:
const rows = $input.all();

const now = DateTime.now().setZone('Asia/Karachi');
const weekStart = now.startOf('week'); // Monday 00:00
const weekEnd   = now.endOf('week');   // Sunday 23:59

const thisWeek = rows.filter(r => {
  const dt = DateTime.fromISO(r.json['Date/Time']);
  return dt >= weekStart && dt <= weekEnd;
});

if (thisWeek.length === 0) {
  return [{ json: {
    html: '<p>No meetings scheduled this week.</p>',
    count: 0
  }}];
}

const statusColor = s =>
  s === 'Scheduled' ? '#3B6D11' :
  s === 'Cancelled' ? '#A32D2D' : '#854F0B';

const tableRows = thisWeek.map(r => `
  <tr style="border-bottom:1px solid #eee">
    <td style="padding:10px 14px;font-weight:500">
      ${r.json.Title}
    </td>
    <td style="padding:10px 14px;color:#555">
      ${r.json['Date/Time'].replace('T',' ').slice(0,16)} PKT
    </td>
    <td style="padding:10px 14px;color:#555">
      ${r.json.Attendees}
    </td>
    <td style="padding:10px 14px;
      color:${statusColor(r.json.Status)};
      font-weight:500">
      ${r.json.Status}
    </td>
    <td style="padding:10px 14px;color:#888;font-size:13px">
      ${r.json.Gist}
    </td>
  </tr>`).join('');

const html = `
<div style="font-family:sans-serif;max-width:720px;color:#222">
  <h2 style="color:#185FA5;margin-bottom:4px">
    Weekly Meeting Digest
  </h2>
  <p style="color:#888;margin-top:0">
    Week of ${weekStart.toFormat('dd MMM')} –
    ${weekEnd.toFormat('dd MMM yyyy')} &nbsp;·&nbsp;
    ${thisWeek.length} meeting(s)
  </p>
  <table style="width:100%;border-collapse:collapse;
    border:1px solid #ddd;border-radius:8px">
    <thead>
      <tr style="background:#f7f7f7">
        <th style="padding:10px 14px;text-align:left;
          font-size:12px;color:#555;font-weight:600">TITLE</th>
        <th style="padding:10px 14px;text-align:left;
          font-size:12px;color:#555;font-weight:600">DATE / TIME</th>
        <th style="padding:10px 14px;text-align:left;
          font-size:12px;color:#555;font-weight:600">ATTENDEES</th>
        <th style="padding:10px 14px;text-align:left;
          font-size:12px;color:#555;font-weight:600">STATUS</th>
        <th style="padding:10px 14px;text-align:left;
          font-size:12px;color:#555;font-weight:600">GIST</th>
      </tr>
    </thead>
    <tbody>${tableRows}</tbody>
  </table>
</div>`;

return [{ json: { html, count: thisWeek.length } }];

const now = DateTime.now();

return $input.all().filter(item => {
  if (!['Scheduled', 'Reminded'].includes(item.json.Status)) return false;

  const start = DateTime.fromISO(item.json['Date/Time']);
  const duration = Number(item.json['Duration'] || 0);
  const end = start.plus({ minutes: duration });

  return start < now;
});

const rows = $input.all();
const now = new Date();
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 30);

const toArchive = rows.filter(r => {
  if (r.json.Status !== 'Done') return false;
  const meetingDate = new Date(r.json['Date/Time']);
  return meetingDate < cutoff;
});

if (toArchive.length === 0) return [];

return toArchive.map(r => ({
  json: {
    ...r.json,
    Status: 'Archived',
    ArchivedOn: now.toISOString()
  }
}));

